            { group: 'Workflow & Ecosystem', items: ['Deep integration with Zotero (Seamlessly syncing massive reference libraries)', 'Shared Collaborative Collections (Allowing entire research teams to work in one graph)', 'Direct PDF Link bridging (Connecting to Open Access repositories)'] }
